using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

// The MCP SDK discovers tools by scanning for [McpServerToolType] classes.
// Each public method marked [McpServerTool] becomes a callable tool.
// Constructor dependencies are resolved from the DI container automatically.

[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _httpClient;

    // The SDK resolves this via DI — see Program.cs where we register
    // IHttpClientFactory with .AddHttpClient().
    public WeatherTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [McpServerTool(Name = "get_weather")]
    [McpServerToolDescription("Get current weather for a city. Returns temperature, conditions, and humidity.")]
    public async Task<string> GetWeatherAsync(
        [McpServerToolParameter(Description = "City name, e.g. 'Seattle' or 'London'")] string city,
        [McpServerToolParameter(Description = "Unit system: 'metric' or 'imperial'", Required = false)] string units = "metric")
    {
        try
        {
            // Example: Open-Meteo geocoding + forecast (free, no API key)
            var geoUrl = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=1";
            var geoResponse = await _httpClient.GetFromJsonAsync<JsonElement>(geoUrl);

            if (!geoResponse.TryGetProperty("results", out var results) || results.GetArrayLength() == 0)
                return $"City '{city}' not found.";

            var location = results[0];
            var lat = location.GetProperty("latitude").GetDouble();
            var lon = location.GetProperty("longitude").GetDouble();
            var name = location.GetProperty("name").GetString();

            var tempUnit = units == "imperial" ? "fahrenheit" : "celsius";
            var forecastUrl = $"https://api.open-meteo.com/v1/forecast?latitude={lat}&longitude={lon}"
                + $"&current=temperature_2m,relative_humidity_2m,weather_code&temperature_unit={tempUnit}";

            var forecast = await _httpClient.GetFromJsonAsync<JsonElement>(forecastUrl);
            var current = forecast.GetProperty("current");

            var temp = current.GetProperty("temperature_2m").GetDouble();
            var humidity = current.GetProperty("relative_humidity_2m").GetInt32();
            var weatherCode = current.GetProperty("weather_code").GetInt32();

            var unitLabel = units == "imperial" ? "°F" : "°C";
            return $"Weather in {name}: {DescribeWeatherCode(weatherCode)}, {temp}{unitLabel}, humidity {humidity}%";
        }
        catch (HttpRequestException ex)
        {
            return $"API request failed: {ex.Message}";
        }
    }

    private static string DescribeWeatherCode(int code) => code switch
    {
        0 => "Clear sky",
        1 or 2 or 3 => "Partly cloudy",
        45 or 48 => "Foggy",
        51 or 53 or 55 => "Drizzle",
        61 or 63 or 65 => "Rain",
        71 or 73 or 75 => "Snow",
        95 => "Thunderstorm",
        _ => $"Weather code {code}"
    };
}

