using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

var builder = Host.CreateApplicationBuilder(args);

// Register a named HttpClient for WeatherTools.
// The MCP SDK instantiates tool classes per-invocation from the DI container,
// so IHttpClientFactory (added by AddHttpClient) provides the HttpClient.
builder.Services.AddHttpClient<McpServer.WeatherTools>();

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

